#include <stdio.h>

void funcA(int n);
void funcB(int n);

void funcA(int n) {
    if (n <= 0) return;
    printf("%d ", n);
    funcB(n - 1);
    printf("%d ", n);
}

void funcB(int n) {
    if (n <= 0) return;
    printf("%d ", n);
    funcA(n % 2);
}

int main() {
    funcA(4);
    return 0;
}

#include <stdio.h>

void f1(int n) {
    if (n <= 0) return;
    printf("%d ", n);
}

void f2(int n) {
    if (n <= 0) return;
    printf("%d ", n - 1);
}

void run(void (*func)(int), int n) {
    func(n);
    if (n > 1)
        run(func == f1 ? f2 : f1, n - 1);
}

int main() {
    void (*p)(int) = f1;
    run(p, 5);
    return 0;
}
